from typing import Any

from langflow.custom import Component
from langflow.io import MessageTextInput, IntInput, Output
from langflow.schema import Data


class TranscriptRouter(Component):
    display_name = "Transcript Router"
    description = "Chooses YouTube transcript if usable, otherwise falls back to Whisper transcript."
    icon = "split"
    name = "TranscriptRouter"

    inputs = [
        MessageTextInput(
            name="youtube_transcript",
            display_name="YouTube Transcript",
            required=False,
        ),
        MessageTextInput(
            name="whisper_transcript",
            display_name="Whisper Transcript",
            required=False,
        ),
        IntInput(
            name="min_youtube_chars",
            display_name="Minimum YouTube Transcript Characters",
            value=500,
        ),
        IntInput(
            name="min_whisper_chars",
            display_name="Minimum Whisper Transcript Characters",
            value=100,
        ),
    ]

    outputs = [
        Output(display_name="Selected Transcript", name="selected_transcript", method="route_transcript"),
    ]

    def _extract_text(self, value: Any) -> str:
        if value is None:
            return ""

        if hasattr(value, "text") and value.text:
            return str(value.text).strip()

        if hasattr(value, "data"):
            data = value.data

            if isinstance(data, dict):
                if "transcript" in data:
                    return str(data.get("transcript", "")).strip()
                if "text" in data:
                    return str(data.get("text", "")).strip()
                return str(data).strip()

            return str(data).strip()

        return str(value).strip()

    def route_transcript(self) -> Data:
        yt = self._extract_text(self.youtube_transcript)
        wh = self._extract_text(self.whisper_transcript)

        if len(yt) >= int(self.min_youtube_chars):
            selected = {
                "transcript": yt,
                "transcript_source": "youtube_transcript",
                "fallback_used": False,
                "selection_reason": "YouTube transcript was available and long enough.",
                "youtube_transcript_chars": len(yt),
                "whisper_transcript_chars": len(wh),
            }
        elif len(wh) >= int(self.min_whisper_chars):
            selected = {
                "transcript": wh,
                "transcript_source": "whisper",
                "fallback_used": True,
                "selection_reason": "YouTube transcript was missing or too short, so Whisper was used.",
                "youtube_transcript_chars": len(yt),
                "whisper_transcript_chars": len(wh),
            }
        else:
            selected = {
                "transcript": "",
                "transcript_source": "none",
                "fallback_used": True,
                "selection_reason": "Neither YouTube transcript nor Whisper transcript was usable.",
                "youtube_transcript_chars": len(yt),
                "whisper_transcript_chars": len(wh),
                "error": "No usable transcript found.",
            }

        self.status = selected
        return Data(data=selected)

import os
import tempfile
import subprocess
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import MessageTextInput, DropdownInput, IntInput, Output
from lfx.schema.data import Data


class OpenSourceWhisperTranscriber(Component):
    display_name = "Open Source Whisper Transcriber"
    description = "Downloads YouTube audio with yt-dlp and transcribes it using local open-source Whisper."
    icon = "mic"
    name = "OpenSourceWhisperTranscriber"

    inputs = [
        MessageTextInput(name="youtube_url", display_name="YouTube URL", required=True),
        DropdownInput(
            name="model_size",
            display_name="Whisper Model Size",
            options=["tiny", "base", "small", "medium"],
            value="small",
        ),
        DropdownInput(
            name="language",
            display_name="Language",
            options=["auto", "en"],
            value="auto",
        ),
        IntInput(name="max_audio_minutes", display_name="Max Audio Minutes", value=30),
    ]

    outputs = [
        Output(display_name="Whisper Transcript", name="whisper_output", method="transcribe_video"),
    ]

    def _to_text(self, value: Any) -> str:
        if value is None:
            return ""
        if hasattr(value, "text"):
            return value.text or ""
        if hasattr(value, "value"):
            return str(value.value)
        if hasattr(value, "data"):
            return str(value.data)
        return str(value)

    def transcribe_video(self) -> Data:
        youtube_url = self._to_text(self.youtube_url).strip()

        if not youtube_url:
            return Data(data={
                "transcript": "",
                "transcript_source": "whisper",
                "success": False,
                "error": "No YouTube URL provided."
            })

        try:
            import whisper
        except Exception as e:
            return Data(data={
                "transcript": "",
                "transcript_source": "whisper",
                "success": False,
                "error": f"Whisper is not installed. Run: pip install -U openai-whisper. Details: {e}"
            })

        with tempfile.TemporaryDirectory() as tmpdir:
            output_template = os.path.join(tmpdir, "audio.%(ext)s")

            cmd = [
                "yt-dlp",
                "-f", "bestaudio/best",
                "--extract-audio",
                "--audio-format", "mp3",
                "--audio-quality", "0",
                "--no-playlist",
                "-o", output_template,
                youtube_url,
            ]

            try:
                subprocess.run(cmd, check=True, capture_output=True, text=True)
            except Exception as e:
                return Data(data={
                    "transcript": "",
                    "transcript_source": "whisper",
                    "success": False,
                    "error": f"yt-dlp audio download failed: {e}"
                })

            audio_path = os.path.join(tmpdir, "audio.mp3")

            if not os.path.exists(audio_path):
                return Data(data={
                    "transcript": "",
                    "transcript_source": "whisper",
                    "success": False,
                    "error": "Audio file was not created. Check yt-dlp and ffmpeg installation."
                })

            try:
                model = whisper.load_model(self.model_size)

                kwargs = {}
                if self.language != "auto":
                    kwargs["language"] = self.language

                result = model.transcribe(
                    audio_path,
                    verbose=False,
                    fp16=False,
                    **kwargs
                )

                transcript = result.get("text", "").strip()

                segments = []
                for seg in result.get("segments", []):
                    start = float(seg.get("start", 0))
                    minutes = int(start // 60)
                    seconds = int(start % 60)
                    timestamp = f"{minutes:02d}:{seconds:02d}"

                    segments.append({
                        "timestamp": timestamp,
                        "text": seg.get("text", "").strip()
                    })

                output = Data(data={
                    "transcript": transcript,
                    "segments": segments,
                    "transcript_source": "whisper",
                    "success": bool(transcript),
                    "language": result.get("language", "unknown"),
                    "model_size": self.model_size,
                    "note": "Generated using local open-source Whisper."
                })

                self.status = output
                return output

            except Exception as e:
                return Data(data={
                    "transcript": "",
                    "transcript_source": "whisper",
                    "success": False,
                    "error": f"Whisper transcription failed: {e}"
                })
